package com.paper.reviewer.export.controller;
import com.paper.reviewer.auth.security.AuthenticatedUser;import com.paper.reviewer.common.ApiResponse;import com.paper.reviewer.export.domain.ReviewExport;import com.paper.reviewer.export.dto.*;import com.paper.reviewer.export.service.ExportService;import org.springframework.core.io.Resource;import org.springframework.http.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController public class ExportController{
 private final ExportService service;public ExportController(ExportService service){this.service=service;}
 @PostMapping("/api/reviews/{reviewId}/exports") public ApiResponse<ExportResponse> review(@AuthenticationPrincipal AuthenticatedUser user,@PathVariable long reviewId,@RequestBody CreateExportRequest request){return ApiResponse.success(ExportResponse.from(service.exportReview(user.userId(),reviewId,request.exportType())));}
 @PostMapping("/api/rereviews/{rereviewId}/exports") public ApiResponse<ExportResponse> rereview(@AuthenticationPrincipal AuthenticatedUser user,@PathVariable long rereviewId,@RequestBody CreateExportRequest request){return ApiResponse.success(ExportResponse.from(service.exportRereview(user.userId(),rereviewId,request.exportType())));}
 @GetMapping("/api/exports/{exportId}") public ResponseEntity<Resource> download(@AuthenticationPrincipal AuthenticatedUser user,@PathVariable long exportId){ReviewExport value=service.get(user.userId(),exportId);Resource resource=service.download(user.userId(),exportId);String extension=value.exportType().name().toLowerCase();return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=review."+extension).contentType(value.exportType()==com.paper.reviewer.export.domain.ExportType.PDF?MediaType.APPLICATION_PDF:MediaType.parseMediaType("text/markdown;charset=UTF-8")).body(resource);}
}
